import type SSOLogger from './logger';
import type { SSOUserInfoType, SSOReturnType, SSOLoginConfig, SSOExchangeTokenByCodeParams, SSOTokenInfoType, RequestType } from '../types';
import { type SSOUserActionType } from '../config/const';
export interface TokenExchangeParamsType {
    clientId: string;
    audience: string[];
    access_token?: string;
    token_exchange_attestation?: string;
}
/**
 * HTTP客户端
 */
export default class HttpClient {
    /**
     * 日志
     */
    private logger;
    /**
     * HTTP请求的Origin
     */
    private origin;
    /**
     * SSO登录配置
     */
    private configs;
    /**
     * 底层请求方法（可选）
     */
    private request?;
    /**
     * 对外SDK版本
     */
    private sdkVersion;
    constructor({ configs, request, logger, sdkVersion, }: {
        configs: SSOLoginConfig;
        request?: RequestType;
        logger: SSOLogger;
        sdkVersion: string;
    });
    /**
     * 获取AccessToken
     * @param accessToken accessToken
     * @returns AccessToken等信息
     */
    getToken(tokenOption?: SSOTokenInfoType): Promise<SSOReturnType<SSOTokenInfoType> | SSOReturnType<null>>;
    /**
     * 获取用户信息
     * @param accessToken accessToken
     * @returns 用户信息
     */
    getUserInfo(accessToken?: string): Promise<SSOReturnType<null> | SSOReturnType<SSOUserInfoType>>;
    /**
     * 登出（仅限CLI工作模式）
     * @param accessToken accessToken
     */
    logout(accessToken?: string): Promise<SSOReturnType<unknown>>;
    /**
     * 上报配置信息
     * @param configs SSO配置
     * @returns
     */
    reportConfig(): Promise<void>;
    /**
     * 某一具体信息
     * @param type 某一具体类型，如登录、tokenExchange
     */
    reportType(actionType: SSOUserActionType): Promise<void>;
    /**
     * 通过code换token
     * @param options 请求配置
     * @returns 操作结果
     */
    exchangeTokenByCode(options: SSOExchangeTokenByCodeParams): Promise<SSOReturnType<SSOTokenInfoType> | SSOReturnType<null>>;
    /**
     * 获取目标clientId的access_token
     * @param options Token Exchange参数
     * @returns 换成后的access_token
     */
    tokenExchange(options: TokenExchangeParamsType): Promise<SSOReturnType<null> | SSOReturnType<{
        access_token: string;
    }>>;
    /**
     * 封装后的请求方法
     * @param param0 请求参数
     * @returns
     */
    private fetchRequest;
    private getReportURL;
    private getLogoutUrl;
    /**
     * 处理请求结果
     * @param data 请求返回数据
     * @param tag 错误TAG
     * @returns 返回结果
     */
    private catchRequestResult;
    /**
     * 捕获并返回结果
     * @param err 错误信息
     * @param tag 错误TAG
     * @returns
     */
    private catchRequestError;
}
